    chain: zod.z.string(),
    vaultAddress: zod.z.string(),
    vaultName: zod.z.string(),
    asset: zod.z.string(),
    currentBalance: amountJsonSchema,
    currentApy: zod.z.number(),
    shares: amountJsonSchema,
    pnl: positionPnlSchema,
